-- ============================================================
-- 01_patient.sql
-- Root entity: a unique individual in the system.
-- ============================================================
-- A patient can have many assessments over time (e.g. for
-- different diabetes reviews). Identity data lives here;
-- clinical data lives in the assessment tables.
-- ============================================================

CREATE TABLE patient (
    -- Primary key: UUIDv4 generated by the database
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),

    -- Patient identity
    full_name       TEXT NOT NULL DEFAULT '',
    date_of_birth   DATE,
    nhs_number      TEXT NOT NULL DEFAULT '',
    address         TEXT NOT NULL DEFAULT '',
    telephone       TEXT NOT NULL DEFAULT '',
    email           TEXT NOT NULL DEFAULT '',
    gp_name         TEXT NOT NULL DEFAULT '',
    gp_practice     TEXT NOT NULL DEFAULT '',

    -- Audit timestamps
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Auto-update updated_at on every row change
CREATE TRIGGER trg_patient_updated_at
    BEFORE UPDATE ON patient
    FOR EACH ROW EXECUTE FUNCTION set_updated_at();

COMMENT ON TABLE patient IS
    'Root entity representing a unique individual. Identity data only; clinical data is per-assessment.';
COMMENT ON COLUMN patient.id IS
    'UUIDv4 primary key, auto-generated.';
COMMENT ON COLUMN patient.full_name IS
    'Patient full name.';
COMMENT ON COLUMN patient.date_of_birth IS
    'Date of birth. NULL if not recorded.';
COMMENT ON COLUMN patient.nhs_number IS
    'NHS number. Empty string if unanswered.';
COMMENT ON COLUMN patient.address IS
    'Patient postal address. Empty string if unanswered.';
COMMENT ON COLUMN patient.telephone IS
    'Patient telephone number. Empty string if unanswered.';
COMMENT ON COLUMN patient.email IS
    'Patient email address. Empty string if unanswered.';
COMMENT ON COLUMN patient.gp_name IS
    'Name of registered GP. Empty string if unanswered.';
COMMENT ON COLUMN patient.gp_practice IS
    'Name of GP practice. Empty string if unanswered.';
COMMENT ON COLUMN patient.created_at IS
    'Row creation timestamp.';
COMMENT ON COLUMN patient.updated_at IS
    'Last modification timestamp, auto-updated by trigger.';
